<script lang="ts">import{ProjectRuntime,runtimeFromManifest}from'@simbot/runtime';import{unpackSimPack}from'@simbot/simpack';import ScreenRenderer from './ScreenRenderer.svelte';let runtime=$state<ProjectRuntime>(demo());let version=$state(0);let title=$state('런타임 데모');let error=$state('');async function load(event:Event){const input=event.currentTarget as HTMLInputElement,file=input.files?.[0];if(!file)return;try{const project=unpackSimPack(new Uint8Array(await file.arrayBuffer()));runtime=new ProjectRuntime(runtimeFromManifest(project.manifest as unknown as Record<string,unknown>));title=project.manifest.title;error='';version+=1;}catch(reason){error=reason instanceof Error?reason.message:String(reason);}}function demo(){return new ProjectRuntime({projectId:'demo',schema:{progression:{sources:{train:[10,10]},thresholds:[30]},time:{startHour:8},initialState:{day:1,gold:0,player:{level:1,exp:0}}},screens:[{id:'play',title:'플레이',layout:'stage-chat-sidebar',regions:{hud:[{widget:'detail-panel',title:'성장',source:'engine:progression/summary'}],main:[{widget:'chat'}],actions:[{widget:'action-group',actions:[{label:'훈련한다',event:{id:'progression/gain',params:{source:'train'}}}]}]}}],navigation:[{id:'play',screenId:'play',label:'플레이'}],content:{},featureToggles:{}});}</script>
<div class="toolbar"><label class="file"><span>SimPack 열기</span><input type="file" accept=".simpack" onchange={load}/></label><strong>{title}</strong>{#if error}<span class="error">{error}</span>{/if}</div><ScreenRenderer {runtime} {version}/>
<style>.toolbar{display:flex;gap:var(--space-3);align-items:center;flex-wrap:wrap;margin-bottom:var(--space-4)}.file{display:inline-flex;align-items:center;min-height:2.6rem;padding:0 var(--space-4);border:1px solid var(--color-line);border-radius:var(--radius-md);cursor:pointer}.file input{position:absolute;inline-size:1px;block-size:1px;opacity:0}.error{color:var(--color-danger)}</style>
